        5 => Action::UpdateMetadataAuthority(random_update_metadata_authority_action(rng)),
        6 => Action::RemoveMetadataKey(random_remove_metadata_key_action(rng)),
        _ => unreachable!(),
    }
}

fn random_cpi_context(rng: &mut StdRng) -> CpiContext {
