207→    /// Calculate the dynamic CPI accounts offset based on which accounts are present
208→    pub fn cpi_accounts_start_offset(&self) -> usize {
209→        // light_system_program & authority (always present)
210→        let mut offset = 2;
211→
212→        // mint_signer (optional)
213→        if self.mint_signer.is_some() {
214→            offset += 1;
215→        }
216→
217→        if let Some(executing) = &self.executing {
218→            // compressible_config (optional) - when creating mint or CMint
219→            if executing.compressible_config.is_some() {
220→                offset += 1;
221→            }
222→            // cmint (optional) - comes before rent_sponsor
223→            if executing.cmint.is_some() {
224→                offset += 1;
225→            }
226→            // rent_sponsor (optional) - when creating mint or CMint
227→            if executing.rent_sponsor.is_some() {
228→                offset += 1;
229→            }
230→            // LightSystemAccounts - CPI accounts start here
231→        }
232→        // write_to_cpi_context_system - these are the CPI accounts that start here
233→        // We don't add them to offset since this is where CPI accounts begin
234→
235→        offset
236→    }
237→
238→    pub fn cpi_accounts_end_offset(&self, deduplicated: bool) -> usize {
239→        if self.write_to_cpi_context_system.is_some() {
240→            self.cpi_accounts_start_offset() + CpiContextLightSystemAccounts::cpi_len()
241→        } else {
242→            let mut offset = self.cpi_accounts_start_offset();
243→            if let Some(executing) = self.executing.as_ref() {
244→                offset += LightSystemAccounts::cpi_len();
245→                if executing.system.sol_pool_pda.is_some() {
246→                    offset += 1;
247→                }
248→                if executing.system.cpi_context.is_some() {
249→                    offset += 1;
250→                }
251→
252→                // out_output_queue (always present)
253→                // Either in_merkle_tree or address_merkle_tree (always present)
254→                offset += 2;
255→                if executing.in_output_queue.is_some() {
256→                    offset += 1;
257→                }
258→                // When deduplicated=false, we need to include the extra queue account
259→                // When deduplicated=true, the duplicate queue is in the outer instruction but not in CPI slice
260→                if executing.tokens_out_queue.is_some() && !deduplicated {
261→                    offset += 1;
262→                }
263→            }
264→            offset
265→        }
266→    }
267→
268→    pub fn get_cpi_accounts<'a>(
269→        &self,
270→        deduplicated: bool,
271→        account_infos: &'a [AccountInfo],
272→    ) -> Result<&'a [AccountInfo], ProgramError> {
273→        let start_offset = self.cpi_accounts_start_offset();
274→        let end_offset = self.cpi_accounts_end_offset(deduplicated);
275→
276→        if end_offset > account_infos.len() {
277→            return Err(ErrorCode::CpiAccountsSliceOutOfBounds.into());
278→        }
279→
280→        Ok(&account_infos[start_offset..end_offset])
281→    }
282→
283→    /// Check if tokens_out_queue exists in executing accounts.
284→    /// Used for queue deduplication logic.
285→    pub fn has_tokens_out_queue(&self) -> bool {
286→        self.executing
287→            .as_ref()
288→            .map(|executing| executing.tokens_out_queue.is_some())
289→            .unwrap_or_else(|| false)
290→    }
291→
292→    /// Check if out_output_queue and tokens_out_queue have the same key.
293→    /// Used for queue index logic when no CPI context is provided.
294→    pub fn queue_keys_match(&self) -> bool {
295→        if let Some(executing) = &self.executing {
296→            if let Some(tokens_out_queue) = executing.tokens_out_queue {
297→                return executing.out_output_queue.key() == tokens_out_queue.key();
298→            }
299→        }
300→        false
301→    }
302→
303→    /// Get CMint account if present in executing accounts.
304→    pub fn get_cmint(&self) -> Option<&'info AccountInfo> {
305→        self.executing.as_ref().and_then(|exec| exec.cmint)
306→    }
307→
308→    pub fn validate_accounts(
309→        &self,
310→        cmint_pubkey: Option<&solana_pubkey::Pubkey>,
311→    ) -> Result<(), ProgramError> {
312→        let accounts = self
313→            .executing
314→            .as_ref()
315→            .ok_or(ProgramError::NotEnoughAccountKeys)?;
316→
317→        // TODO: check whether we can simplify or move to decompress action processor.
318→        // When cmint_pubkey is provided, verify CMint account matches
319→        // When None (mint data from CMint), skip - CMint is validated when reading its data
320→        if let (Some(cmint_account), Some(expected_pubkey)) = (accounts.cmint, cmint_pubkey) {
321→            if expected_pubkey.to_bytes() != *cmint_account.key() {
322→                return Err(ErrorCode::MintAccountMismatch.into());
323→            }
324→        }
325→
326→        // Validate address merkle tree when creating mint
327→        if let Some(address_tree) = accounts.address_merkle_tree {
328→            if *address_tree.key() != MINT_ADDRESS_TREE {
329→                msg!(
330→                    "Create mint action expects address Merkle tree {:?} received: {:?}",
331→                    solana_pubkey::Pubkey::from(MINT_ADDRESS_TREE),
332→                    solana_pubkey::Pubkey::from(*address_tree.key())
333→                );
334→                return Err(ErrorCode::InvalidAddressTree.into());
335→            }
336→        }
337→
338→        Ok(())
339→    }
340→}
