342→/// Config to parse AccountInfos based on instruction data.
343→/// We use instruction data to convey which accounts are expected.
344→#[derive(Debug, PartialEq)]
345→pub struct AccountsConfig {
346→    /// 1. cpi context is some
347→    pub with_cpi_context: bool,
348→    /// 2. cpi context.first_set() || cpi context.set()
349→    pub write_to_cpi_context: bool,
350→    /// 4. Whether the compressed mint has been decompressed to a CMint Solana account.
351→    ///    When true, the CMint account is the decompressed (compressed account is empty).
352→    pub cmint_decompressed: bool,
353→    /// 5. Mint
354→    pub require_token_output_queue: bool,
355→    /// 6. Compressed mint is created.
356→    pub with_mint_signer: bool,
357→    /// 7. Compressed mint is created.
358→    pub create_mint: bool,
359→    /// 8. Has DecompressMint action
360→    pub has_decompress_mint_action: bool,
361→    /// 9. Has CompressAndCloseCMint action
362→    pub has_compress_and_close_cmint_action: bool,
363→}
364→
365→impl AccountsConfig {
366→    /// Returns true when CMint Solana account is the decompressed for mint data.
367→    /// This is the case when the mint is decompressed (or being decompressed) and not being closed.
368→    /// When true, compressed account uses zero sentinel values (discriminator=[0;8], data_hash=[0;32]).
369→    #[inline(always)]
370→    pub fn cmint_output_decompressed(&self) -> bool {
371→        (self.has_decompress_mint_action || self.cmint_decompressed)
372→            && !self.has_compress_and_close_cmint_action
373→    }
374→
375→    /// Returns true if compressible extension accounts are needed.
376→    /// Required for DecompressMint and CompressAndCloseCMint actions.
377→    #[inline(always)]
378→    pub fn needs_compressible_accounts(&self) -> bool {
379→        self.has_decompress_mint_action || self.has_compress_and_close_cmint_action
380→    }
381→
382→    /// Returns true if rent_sponsor account is needed.
383→    /// Required when creating a new mint (mint creation fee recipient) or when compressible accounts are needed.
384→    #[inline(always)]
385→    pub fn needs_rent_sponsor(&self) -> bool {
386→        self.create_mint || self.needs_compressible_accounts()
387→    }
388→
389→    /// Returns true if CMint account is needed in the transaction.
390→    /// Required when: already decompressed, decompressing, or compressing and closing CMint.
391→    #[inline(always)]
392→    pub fn needs_cmint_account(&self) -> bool {
393→        self.cmint_decompressed
394→            || self.has_decompress_mint_action
395→            || self.has_compress_and_close_cmint_action
396→    }
397→
398→    /// Returns true if mint_signer must be a signer.
399→    /// Required for create_mint, but NOT for decompress_mint.
400→    /// decompress_mint only needs mint_signer.key() for PDA derivation.
401→    #[inline(always)]
402→    pub fn mint_signer_must_sign(&self) -> bool {
403→        self.create_mint
404→    }
405→
406→    /// Initialize AccountsConfig based in instruction data.  -
407→    #[profile]
408→    pub fn new(
409→        parsed_instruction_data: &ZMintActionCompressedInstructionData,
410→    ) -> Result<AccountsConfig, ProgramError> {
411→        if let Some(create_mint) = parsed_instruction_data.create_mint.as_ref() {
412→            if [0u8; 4] != create_mint.read_only_address_trees {
413→                msg!("read_only_address_trees must be 0");
414→                return Err(ProgramError::InvalidInstructionData);
415→            }
416→            if [U16::from(0); 4] != create_mint.read_only_address_tree_root_indices {
417→                msg!("read_only_address_tree_root_indices must be 0");
418→                return Err(ProgramError::InvalidInstructionData);
419→            }
420→        }
421→
422→        // 1.cpi context
423→        let with_cpi_context = parsed_instruction_data.cpi_context.is_some();
424→
425→        // 2. write to cpi context
426→        let write_to_cpi_context = parsed_instruction_data
427→            .cpi_context
428→            .as_ref()
429→            .map(|x| x.first_set_context() || x.set_context())
430→            .unwrap_or_default();
431→
432→        // Check if DecompressMint action is present
433→        let has_decompress_mint_action = parsed_instruction_data
434→            .actions
435→            .iter()
436→            .any(|action| matches!(action, ZAction::DecompressMint(_)));
437→
438→        // Check if CompressAndCloseCMint action is present
439→        let has_compress_and_close_cmint_action = parsed_instruction_data
440→            .actions
441→            .iter()
442→            .any(|action| matches!(action, ZAction::CompressAndCloseMint(_)));
443→
444→        // Validation: Cannot combine DecompressMint and CompressAndCloseCMint in the same instruction
445→        if has_decompress_mint_action && has_compress_and_close_cmint_action {
446→            msg!("Cannot combine DecompressMint and CompressAndCloseCMint in the same instruction");
447→            return Err(ErrorCode::CannotDecompressAndCloseInSameInstruction.into());
448→        }
449→
450→        // Validation: CompressAndCloseCMint must be the only action
451→        if has_compress_and_close_cmint_action && parsed_instruction_data.actions.len() != 1 {
452→            msg!("CompressAndCloseCMint must be the only action in the instruction");
453→            return Err(ErrorCode::CompressAndCloseCMintMustBeOnlyAction.into());
454→        }
455→
456→        // Validation: Cannot combine create_mint with CompressAndCloseCMint
457→        if has_compress_and_close_cmint_action && parsed_instruction_data.create_mint.is_some() {
458→            msg!("Cannot combine create_mint with CompressAndCloseCMint");
459→            return Err(ErrorCode::CompressAndCloseCMintMustBeOnlyAction.into());
460→        }
461→
462→        // We need mint signer only if creating a new mint.
463→        // CompressAndCloseCMint does NOT need mint_signer - it verifies CMint by compressed_mint.metadata.mint
464→        let with_mint_signer = parsed_instruction_data.create_mint.is_some();
465→        // CMint account needed when mint is already decompressed (metadata flag)
466→        // When mint is None, CMint is decompressed (data lives in CMint account, compressed account is empty)
467→        let cmint_decompressed = parsed_instruction_data.mint.is_none();
468→
469→        if write_to_cpi_context {
470→            // Cannot create a compressed mint when writing to CPI context.
471→            // Mint creation charges the creation fee and requires the rent_sponsor account,
472→            // which is not available in the CPI context write path.
473→            if parsed_instruction_data.create_mint.is_some() {
474→                msg!("Compressed mint creation not allowed when writing to cpi context");
475→                return Err(ErrorCode::CpiContextSetNotUsable.into());
476→            }
477→
478→            // Must not have any MintToCToken actions
479→            let has_mint_to_ctoken_actions = parsed_instruction_data
480→                .actions
481→                .iter()
482→                .any(|action| matches!(action, ZAction::MintTo(_)));
483→            if has_mint_to_ctoken_actions {
484→                msg!("Mint to ctokens not allowed when writing to cpi context");
485→                return Err(ErrorCode::CpiContextSetNotUsable.into());
486→            }
487→            if has_decompress_mint_action {
488→                msg!("Decompress mint not allowed when writing to cpi context");
489→                return Err(ErrorCode::CpiContextSetNotUsable.into());
490→            }
491→
492→            if cmint_decompressed {
493→                msg!("CMint decompressed not allowed when writing to cpi context");
494→                return Err(ErrorCode::CpiContextSetNotUsable.into());
495→            }
496→            let require_token_output_queue = parsed_instruction_data
497→                .actions
498→                .iter()
499→                .any(|action| matches!(action, ZAction::MintToCompressed(_)));
500→            Ok(AccountsConfig {
501→                with_cpi_context,
502→                write_to_cpi_context,
503→                cmint_decompressed,
504→                require_token_output_queue,
505→                with_mint_signer,
506→                create_mint: parsed_instruction_data.create_mint.is_some(),
507→                has_decompress_mint_action,
508→                has_compress_and_close_cmint_action,
509→            })
510→        } else {
511→            // For MintToCompressed actions
512→            // - needed for tokens_out_queue (only MintToCompressed creates new compressed outputs)
513→            // - MintToCToken mints to existing decompressed accounts, doesn't need tokens_out_queue
514→            let require_token_output_queue = parsed_instruction_data
515→                .actions
516→                .iter()
517→                .any(|action| matches!(action, ZAction::MintToCompressed(_)));
518→
519→            Ok(AccountsConfig {
520→                with_cpi_context,
521→                write_to_cpi_context,
522→                cmint_decompressed,
523→                require_token_output_queue,
524→                with_mint_signer,
525→                create_mint: parsed_instruction_data.create_mint.is_some(),
526→                has_decompress_mint_action,
527→                has_compress_and_close_cmint_action,
528→            })
529→        }
530→    }
531→}
