 27→
 28→pub fn process_mint_action(
 29→    accounts: &[AccountInfo],
 30→    instruction_data: &[u8],
 31→) -> Result<(), ProgramError> {
 32→    // 1. parse instruction data
 33→    // 677 CU
 34→    let (parsed_instruction_data, _) =
 35→        MintActionCompressedInstructionData::zero_copy_at(instruction_data)
 36→            .map_err(|_| ProgramError::InvalidInstructionData)?;
 37→    // 112 CU write to cpi contex
 38→    let accounts_config = AccountsConfig::new(&parsed_instruction_data)?;
 39→    // Get mint pubkey from instruction data if present
 40→    let cmint_pubkey: Option<solana_pubkey::Pubkey> = parsed_instruction_data
 41→        .mint
 42→        .as_ref()
 43→        .map(|m| m.metadata.mint.into());
 44→    // Validate and parse
 45→    let validated_accounts =
 46→        MintActionAccounts::validate_and_parse(accounts, &accounts_config, cmint_pubkey.as_ref())?;
 47→
 48→    // Charge mint creation fee. create_mint is rejected in CPI context write path
 49→    // (validated in AccountsConfig::new), so executing and rent_sponsor are always present here.
 50→    if accounts_config.create_mint {
 51→        let executing = validated_accounts
 52→            .executing
 53→            .as_ref()
 54→            .ok_or(ErrorCode::MintActionMissingExecutingAccounts)?;
 55→        let rent_sponsor = executing
 56→            .rent_sponsor
 57→            .ok_or(ErrorCode::MintActionMissingExecutingAccounts)?;
 58→        // Validate rent_sponsor matches config to prevent fee bypass.
 59→        let config = executing
 60→            .compressible_config
 61→            .ok_or(ErrorCode::MintActionMissingExecutingAccounts)?;
 62→        if rent_sponsor.key() != &config.rent_sponsor.to_bytes() {
 63→            msg!("Rent sponsor account does not match config");
 64→            return Err(ErrorCode::InvalidRentSponsor.into());
 65→        }
 66→        transfer_lamports_via_cpi(MINT_CREATION_FEE, executing.system.fee_payer, rent_sponsor)
 67→            .map_err(convert_program_error)?;
 68→    }
 69→
 70→    // Get mint data based on source:
 71→    // 1. Creating new mint: mint data required in instruction
 72→    // 2. Existing compressed mint: mint data in instruction (cmint_decompressed = false)
 73→    // 3. CMint is decompressed: read from CMint account (cmint_decompressed = true)
 74→    let mint = if accounts_config.create_mint {
 75→        // Creating new mint - mint data required in instruction
 76→        let mint_data = parsed_instruction_data
 77→            .mint
 78→            .as_ref()
 79→            .ok_or(ErrorCode::MintDataRequired)?;
 80→        Mint::try_from(mint_data)?
 81→    } else if !accounts_config.cmint_decompressed {
 82→        // Existing compressed mint with data in instruction
 83→        // In case that cmint is not actually compressed proof verification will fail.
 84→        let mint_data = parsed_instruction_data
 85→            .mint
 86→            .as_ref()
 87→            .ok_or(ErrorCode::MintDataRequired)?;
 88→        Mint::try_from(mint_data)?
 89→    } else {
 90→        // CMint is decompressed - read from CMint account
 91→        let cmint_account = validated_accounts
 92→            .get_cmint()
 93→            .ok_or(ErrorCode::MintActionMissingCMintAccount)?;
 94→        Mint::from_account_info_checked(cmint_account)?
 95→    };
 96→
 97→    let (config, mut cpi_bytes, _) =
 98→        get_zero_copy_configs(&parsed_instruction_data, &accounts_config, &mint)?;
 99→    let (mut cpi_instruction_struct, remaining_bytes) =
100→        InstructionDataInvokeCpiWithReadOnly::new_zero_copy(&mut cpi_bytes[8..], config)
101→            .map_err(ProgramError::from)?;
102→    assert!(remaining_bytes.is_empty());
103→    cpi_instruction_struct.initialize(
104→        crate::LIGHT_CPI_SIGNER.bump,
105→        &crate::LIGHT_CPI_SIGNER.program_id.into(),
106→        parsed_instruction_data.proof,
107→        &parsed_instruction_data.cpi_context,
108→    )?;
109→    if !accounts_config.write_to_cpi_context
110→        && !parsed_instruction_data.prove_by_index()
111→        && parsed_instruction_data.proof.is_none()
112→    {
113→        return Err(ErrorCode::MintActionProofMissing.into());
114→    }
115→
116→    let mut hash_cache = HashCache::new();
117→    let tokens_out_queue_exists = validated_accounts.has_tokens_out_queue();
118→    let queue_keys_match = validated_accounts.queue_keys_match();
119→    let queue_indices = QueueIndices::new(
120→        parsed_instruction_data.cpi_context.as_ref(),
121→        accounts_config.create_mint,
122→        tokens_out_queue_exists,
123→        queue_keys_match,
124→        accounts_config.write_to_cpi_context,
125→    )?;
126→
127→    // Get mint data based on instruction type:
128→    // 1. Creating mint: mint data from instruction (must be Some)
129→    // 2. Existing mint with data in instruction: use instruction data
130→    // 3. Existing decompressed mint (CMint): read from CMint account
131→    if accounts_config.create_mint {
132→        // Creating new mint - mint data required in instruction
133→        process_create_mint_action(
134→            &parsed_instruction_data,
135→            validated_accounts
136→                .mint_signer
137→                .ok_or(TokenError::ExpectedMintSignerAccount)
138→                .map_err(|_| ErrorCode::MintActionMissingExecutingAccounts)?
139→                .key(),
140→            &mut cpi_instruction_struct,
141→            queue_indices.address_merkle_tree_index,
142→        )?;
143→    } else {
144→        // Existing mint - set input compressed account
145→        // When CMint is decompressed, input has zero values
146→        // When data from instruction, input has real data hash
147→        create_input_compressed_mint_account(
148→            &mut cpi_instruction_struct.input_compressed_accounts[0],
149→            parsed_instruction_data.root_index,
150→            PackedMerkleContext {
151→                merkle_tree_pubkey_index: queue_indices.in_tree_index,
152→                queue_pubkey_index: queue_indices.in_queue_index,
153→                leaf_index: parsed_instruction_data.leaf_index.into(),
154→                prove_by_index: parsed_instruction_data.prove_by_index(),
155→            },
156→            &accounts_config,
157→            &mint,
158→        )?;
159→    }
160→
161→    let result = process_output_compressed_account(
162→        &parsed_instruction_data,
163→        &validated_accounts,
164→        &mut cpi_instruction_struct.output_compressed_accounts,
165→        &mut hash_cache,
166→        &queue_indices,
167→        mint,
168→        &accounts_config,
169→    );
170→
171→    // Check for idempotent early exit - skip CPI and return success.
172→    // create_mint must never use idempotent early exit (fee already charged).
173→    if let Err(ref err) = result {
174→        if is_idempotent_early_exit(err) {
175→            if accounts_config.create_mint {
176→                return Err(ErrorCode::MintActionMissingExecutingAccounts.into());
177→            }
178→            return Ok(());
179→        }
180→    }
181→    result?;
182→
183→    let cpi_accounts = validated_accounts.get_cpi_accounts(queue_indices.deduplicated, accounts)?;
184→    if let Some(executing) = validated_accounts.executing.as_ref() {
185→        // Execute CPI to light-system-program
186→        execute_cpi_invoke(
187→            cpi_accounts,
188→            cpi_bytes,
189→            validated_accounts
190→                .tree_pubkeys(queue_indices.deduplicated)
191→                .as_slice(),
192→            false, // no sol_pool_pda
193→            None,
194→            executing.system.cpi_context.map(|x| *x.key()),
195→            false, // don't write to cpi context account
196→        )
197→    } else {
198→        if validated_accounts.write_to_cpi_context_system.is_none() {
199→            return Err(ErrorCode::CpiContextExpected.into());
200→        }
201→        execute_cpi_invoke(
202→            cpi_accounts,
203→            cpi_bytes,
204→            &[],
205→            false, // no sol_pool_pda
206→            None,
207→            validated_accounts
208→                .write_to_cpi_context_system
209→                .as_ref()
210→                .map(|x| *x.cpi_context.key()),
211→            true,
212→        )
213→    }
214→}
