 19→pub struct MintActionAccounts<'info> {
 20→    pub light_system_program: &'info AccountInfo,
 21→    /// Seed for mint PDA derivation.
 22→    /// Required only for compressed mint creation.
 23→    /// Note: mint_signer is not in executing accounts since it is parsed
 24→    /// before the executing/cpi-write branch. create_mint is NOT allowed
 25→    /// in combination with write to cpi context (rejected in AccountsConfig::new).
 26→    pub mint_signer: Option<&'info AccountInfo>,
 27→    pub authority: &'info AccountInfo,
 28→    /// Required accounts to execute an instruction
 29→    /// with or without cpi context.
 30→    /// - write_to_cpi_context_system is None
 31→    pub executing: Option<ExecutingAccounts<'info>>,
 32→    /// Required accounts to write into a cpi context account.
 33→    /// - executing is None
 34→    pub write_to_cpi_context_system: Option<CpiContextLightSystemAccounts<'info>>,
 35→    /// Packed accounts contain
 36→    /// [
 37→    ///     ..tree_accounts,
 38→    ///     ..recipient_token_accounts (mint_to_ctoken)
 39→    /// ]
 40→    pub packed_accounts: ProgramPackedAccounts<'info, AccountInfo>,
 41→}
