 43→/// Required accounts to execute an instruction
 44→/// with or without cpi context.
 45→pub struct ExecutingAccounts<'info> {
 46→    /// CompressibleConfig - parsed and validated (active state) when creating CMint.
 47→    pub compressible_config: Option<&'info CompressibleConfig>,
 48→    /// CMint Solana account (decompressed compressed mint).
 49→    /// Required for DecompressMint, CompressAndCloseCMint, and operations on decompressed mints.
 50→    pub cmint: Option<&'info AccountInfo>,
