 68→impl<'info> MintActionAccounts<'info> {
 69→    #[profile]
 70→    #[track_caller]
 71→    pub fn validate_and_parse(
 72→        accounts: &'info [AccountInfo],
 73→        config: &AccountsConfig,
 74→        cmint_pubkey: Option<&solana_pubkey::Pubkey>,
 75→    ) -> Result<Self, ProgramError> {
 76→        let mut iter = AccountIterator::new(accounts);
 77→        let light_system_program = iter.next_account("light_system_program")?;
 78→
 79→        // mint_signer needs to sign for create_mint, but not for decompress_mint
 80→        let mint_signer = if config.mint_signer_must_sign() {
 81→            iter.next_option_signer("mint_signer", config.with_mint_signer)?
 82→        } else {
 83→            None
 84→        };
 85→        // Static non-CPI accounts first
 86→        // Authority is always required to sign
 87→        let authority = iter.next_signer("authority")?;
 88→        if config.write_to_cpi_context {
 89→            let write_to_cpi_context_system = CpiContextLightSystemAccounts::new(&mut iter)?;
 90→
 91→            if !iter.iterator_is_empty() {
 92→                msg!("Too many accounts for write to cpi context.");
 93→                return Err(ProgramError::InvalidAccountData);
 94→            }
 95→            Ok(MintActionAccounts {
 96→                light_system_program,
 97→                mint_signer,
 98→                authority,
 99→                executing: None,
100→                write_to_cpi_context_system: Some(write_to_cpi_context_system),
101→                packed_accounts: ProgramPackedAccounts { accounts: &[] },
102→            })
103→        } else {
104→            // Parse and validate compressible config when creating mint (fee validation),
105→            // decompressing, or closing CMint
106→            let compressible_config = if config.create_mint || config.needs_compressible_accounts()
107→            {
108→                Some(next_config_account(&mut iter)?)
109→            } else {
110→                None
111→            };
112→
113→            // CMint account required if already decompressed OR being decompressed/closed
114→            let cmint = iter.next_option_mut("cmint", config.needs_cmint_account())?;
115→
116→            // Parse rent_sponsor when creating mint (fee recipient) or when creating/closing CMint
117→            let rent_sponsor = iter.next_option_mut("rent_sponsor", config.needs_rent_sponsor())?;
118→
119→            let system = LightSystemAccounts::validate_and_parse(
120→                &mut iter,
121→                false,
122→                false,
123→                config.with_cpi_context,
124→            )?;
125→            let out_output_queue = iter.next_account("out_output_queue")?;
126→
127→            // Parse merkle tree based on whether we're creating or updating mint
128→            let (in_merkle_tree, address_merkle_tree) = if config.create_mint {
129→                // Creating mint: next account is address merkle tree
130→                let address_tree = iter.next_account("address_merkle_tree")?;
131→                (None, Some(address_tree))
132→            } else {
133→                // Existing mint: next account is in merkle tree
134→                let in_tree = iter.next_account("in_merkle_tree")?;
135→                (Some(in_tree), None)
136→            };
137→
138→            let in_output_queue = iter.next_option("in_output_queue", !config.create_mint)?;
139→            // Only needed for minting to compressed token accounts
140→            let tokens_out_queue =
141→                iter.next_option("tokens_out_queue", config.require_token_output_queue)?;
142→
143→            let mint_accounts = MintActionAccounts {
144→                mint_signer,
145→                light_system_program,
146→                authority,
147→                executing: Some(ExecutingAccounts {
148→                    compressible_config,
149→                    cmint,
150→                    rent_sponsor,
151→                    system,
152→                    in_merkle_tree,
153→                    address_merkle_tree,
154→                    in_output_queue,
155→                    out_output_queue,
156→                    tokens_out_queue,
157→                }),
158→                write_to_cpi_context_system: None,
159→                packed_accounts: ProgramPackedAccounts {
160→                    accounts: iter.remaining_unchecked()?,
161→                },
162→            };
163→            mint_accounts.validate_accounts(cmint_pubkey)?;
164→
165→            Ok(mint_accounts)
166→        }
167→    }
