 6→/// A transfer instruction containing the recipient account and amount
 7→#[derive(Debug)]
 8→pub struct Transfer<'a> {
 9→    pub account: &'a AccountInfo,
10→    pub amount: u64,
11→}
12→
13→#[inline(always)]
14→#[profile]
15→pub fn transfer_lamports(
16→    amount: u64,
17→    from: &AccountInfo,
18→    to: &AccountInfo,
19→) -> Result<(), ProgramError> {
20→    let from_lamports: u64 = *from.try_borrow_lamports()?;
21→    let to_lamports: u64 = *to.try_borrow_lamports()?;
22→    if from_lamports < amount {
23→        msg!("payer lamports {}", from_lamports);
24→        msg!("required lamports {}", amount);
25→        return Err(ProgramError::InsufficientFunds);
26→    }
27→
28→    let from_lamports = from_lamports
29→        .checked_sub(amount)
30→        .ok_or(ProgramError::InsufficientFunds)?;
31→    let to_lamports = to_lamports
32→        .checked_add(amount)
33→        .ok_or(ProgramError::InsufficientFunds)?;
34→    *from.try_borrow_mut_lamports()? = from_lamports;
35→    *to.try_borrow_mut_lamports()? = to_lamports;
36→    Ok(())
37→}
38→
39→/// Transfer lamports using CPI to system program
40→/// This is needed when transferring from accounts not owned by our program
41→#[cold]
42→#[profile]
43→pub fn transfer_lamports_via_cpi(
44→    amount: u64,
45→    from: &AccountInfo,
46→    to: &AccountInfo,
47→) -> Result<(), ProgramError> {
48→    let transfer = SystemTransfer {
49→        from,
50→        to,
51→        lamports: amount,
52→    };
53→
54→    transfer.invoke()
55→}
