57→/// Multi-transfer optimization that performs a single CPI and manual transfers (pinocchio version)
58→///
59→/// Transfers the total amount to the first recipient via CPI, then manually
60→/// transfers from the first recipient to subsequent recipients. This reduces
61→/// the number of CPIs from N to 1.
62→#[inline(always)]
63→#[profile]
64→pub fn multi_transfer_lamports(
65→    payer: &AccountInfo,
66→    transfers: &[Transfer],
67→) -> Result<(), ProgramError> {
68→    // Calculate total amount needed
69→    let total_amount: u64 = transfers
70→        .iter()
71→        .map(|t| t.amount)
72→        .try_fold(0u64, |acc, amt| acc.checked_add(amt))
73→        .ok_or(ProgramError::ArithmeticOverflow)?;
74→
75→    if total_amount == 0 {
76→        return Ok(());
77→    }
78→
79→    // Single CPI to transfer total amount to first recipient
80→    let first_recipient = transfers[0].account;
81→    transfer_lamports_via_cpi(total_amount, payer, first_recipient)?;
82→
83→    // Manual transfers from first recipient to subsequent recipients
84→    for transfer in transfers.iter().skip(1) {
85→        if transfer.amount > 0 {
86→            transfer_lamports(transfer.amount, first_recipient, transfer.account)?;
87→        }
88→    }
89→
90→    Ok(())
91→}
