147→/// Generates random MintActionCompressedInstructionData with controllable parameters
148→fn generate_random_instruction_data(
149→    rng: &mut StdRng,
150→    force_create_mint: Option<bool>,
151→    force_cpi_context: Option<bool>,
152→    force_spl_initialized: Option<bool>,
153→    action_count_range: std::ops::Range<usize>,
154→) -> MintActionCompressedInstructionData {
155→    let create_mint = force_create_mint.unwrap_or_else(|| rng.gen_bool(0.3));
156→    let create_mint = if create_mint {
157→        Some(CreateMint::default())
158→    } else {
159→        None
160→    };
161→    let has_cpi_context = force_cpi_context.unwrap_or_else(|| rng.gen_bool(0.4));
162→
163→    let mut mint_metadata = random_compressed_mint_metadata(rng);
164→    if let Some(spl_init) = force_spl_initialized {
165→        mint_metadata.mint_decompressed = spl_init && create_mint.is_none();
166→    }
167→
168→    // Generate actions
169→    let action_count = rng.gen_range(action_count_range);
170→    let mut actions = Vec::with_capacity(action_count);
171→    for _ in 0..action_count {
172→        actions.push(random_action(rng));
173→    }
174→
175→    MintActionCompressedInstructionData {
176→        create_mint,
177→        leaf_index: rng.gen::<u32>(),
178→        prove_by_index: rng.gen_bool(0.5),
179→        root_index: rng.gen::<u16>(),
180→        max_top_up: rng.gen::<u16>(),
181→        actions,
182→        proof: if rng.gen_bool(0.6) {
183→            Some(random_compressed_proof(rng))
184→        } else {
185→            None
186→        },
187→        cpi_context: if has_cpi_context {
188→            Some(random_cpi_context(rng))
189→        } else {
190→            None
191→        },
192→        mint: Some(MintInstructionData {
193→            supply: rng.gen_range(0..=1_000_000_000),
194→            decimals: rng.gen_range(0..=9),
195→            metadata: mint_metadata,
196→            mint_authority: random_optional_pubkey(rng, 0.9),
197→            freeze_authority: random_optional_pubkey(rng, 0.7),
198→            extensions: if rng.gen_bool(0.3) {
199→                Some(vec![random_token_metadata_extension(rng)])
200→            } else {
201→                None
202→            },
203→        }),
204→    }
205→}
