207→/// Computes expected AccountsConfig based on instruction data
208→fn compute_expected_config(data: &MintActionCompressedInstructionData) -> AccountsConfig {
209→    // 1. with_cpi_context
210→    let with_cpi_context = data.cpi_context.is_some();
211→
212→    // 2. write_to_cpi_context
213→    let write_to_cpi_context = data
214→        .cpi_context
215→        .as_ref()
216→        .map(|ctx| ctx.first_set_context || ctx.set_context)
217→        .unwrap_or(false);
218→
219→    // 3. require_token_output_queue (only MintToCompressed creates new compressed outputs)
220→    let require_token_output_queue = data
221→        .actions
222→        .iter()
223→        .any(|action| matches!(action, Action::MintToCompressed(_)));
224→
225→    // 4. mint_decompressed - only based on metadata flag (matches AccountsConfig::new)
226→    let cmint_decompressed = data.mint.as_ref().unwrap().metadata.mint_decompressed;
227→
228→    // 5. with_mint_signer
229→    let with_mint_signer = data.create_mint.is_some();
230→
231→    // 7. create_mint
232→    let create_mint = data.create_mint.is_some();
233→
234→    // 8. has_decompress_mint_action
235→    let has_decompress_mint_action = data
236→        .actions
237→        .iter()
238→        .any(|action| matches!(action, Action::DecompressMint(_)));
239→
240→    // 9. has_compress_and_close_cmint_action
241→    let has_compress_and_close_cmint_action = data
242→        .actions
243→        .iter()
244→        .any(|action| matches!(action, Action::CompressAndCloseMint(_)));
245→
246→    AccountsConfig {
247→        with_cpi_context,
248→        has_decompress_mint_action,
249→        has_compress_and_close_cmint_action,
250→        write_to_cpi_context,
251→        cmint_decompressed,
252→        require_token_output_queue,
253→        with_mint_signer,
254→        create_mint,
255→    }
256→}
