262→#[test]
263→fn test_accounts_config_randomized() {
264→    let mut rng = thread_rng();
265→    let seed: u64 = rng.gen();
266→    println!("seed value: {}", seed);
267→    let mut rng = StdRng::seed_from_u64(seed);
268→
269→    for _ in 0..1000 {
270→        // Generate random instruction data
271→        let instruction_data = generate_random_instruction_data(
272→            &mut rng,
273→            Some(true), // Random create_mint
274→            Some(true), // Random cpi_context
275→            Some(true), // Random spl_initialized
276→            0..6,       // 1-5 actions
277→        );
278→        // Serialize to bytes then deserialize as zero-copy
279→        let serialized = instruction_data.try_to_vec().expect("Failed to serialize");
280→        let (zero_copy_data, _) = MintActionCompressedInstructionData::zero_copy_at(&serialized)
281→            .expect("Failed to deserialize as zero-copy");
282→
283→        // Check if this configuration should error
284→        let should_error = check_if_config_should_error(&instruction_data);
285→
286→        // Generate actual config
287→        let actual_config_result = AccountsConfig::new(&zero_copy_data);
288→
289→        if should_error {
290→            // Verify that it returns the expected error
291→            assert!(
292→                actual_config_result.is_err(),
293→                "Expected error for instruction data but got Ok. CPI context: {:?}, Actions: {:?}",
294→                instruction_data.cpi_context,
295→                instruction_data.actions
296→            );
297→
298→            // Verify the specific error code
299→            let error = actual_config_result.unwrap_err();
300→            assert_eq!(
301→                error,
302→                light_compressed_token::ErrorCode::CpiContextSetNotUsable.into(),
303→                "Expected CpiContextSetNotUsable error but got {:?}",
304→                error
305→            );
306→        } else {
307→            // Compute expected config
308→            let expected_config = compute_expected_config(&instruction_data);
309→
310→            // Should succeed
311→            let actual_config =
312→                actual_config_result.expect("AccountsConfig::new failed unexpectedly");
313→            assert_eq!(expected_config, actual_config);
314→        }
315→    }
316→}
