318→/// Check if the given instruction data should result in an error
319→fn check_if_config_should_error(instruction_data: &MintActionCompressedInstructionData) -> bool {
320→    // Check if write_to_cpi_context is true
321→    let write_to_cpi_context = instruction_data
322→        .cpi_context
323→        .as_ref()
324→        .map(|x| x.first_set_context || x.set_context)
325→        .unwrap_or_default();
326→
327→    if write_to_cpi_context {
328→        // Check for MintToCToken actions
329→        let has_mint_to_ctoken = instruction_data
330→            .actions
331→            .iter()
332→            .any(|action| matches!(action, Action::MintTo(_)));
333→
334→        // Check for MintToCompressed actions
335→        let require_token_output_queue = instruction_data
336→            .actions
337→            .iter()
338→            .any(|action| matches!(action, Action::MintToCompressed(_)));
339→
340→        // mint_decompressed is only from metadata flag (matches AccountsConfig::new)
341→        let mint_decompressed = instruction_data
342→            .mint
343→            .as_ref()
344→            .unwrap()
345→            .metadata
346→            .mint_decompressed;
347→
348→        // Check if this is creating a new mint (not from an existing compressed mint)
349→        let is_creating_mint = instruction_data.mint.is_none();
350→
351→        // Check if create_mint is set (create_mint + write_to_cpi_context not allowed)
352→        let create_mint_with_cpi_write = instruction_data.create_mint.is_some();
353→
