223→            if executing.cmint.is_some() {
224→                offset += 1;
225→            }
226→            // rent_sponsor (optional) - when creating mint or CMint
227→            if executing.rent_sponsor.is_some() {
228→                offset += 1;
229→            }
230→            // LightSystemAccounts - CPI accounts start here
231→        }
232→        // write_to_cpi_context_system - these are the CPI accounts that start here
233→        // We don't add them to offset since this is where CPI accounts begin
234→
235→        offset
