238→    pub fn cpi_accounts_end_offset(&self, deduplicated: bool) -> usize {
239→        if self.write_to_cpi_context_system.is_some() {
240→            self.cpi_accounts_start_offset() + CpiContextLightSystemAccounts::cpi_len()
241→        } else {
242→            let mut offset = self.cpi_accounts_start_offset();
243→            if let Some(executing) = self.executing.as_ref() {
244→                offset += LightSystemAccounts::cpi_len();
245→                if executing.system.sol_pool_pda.is_some() {
246→                    offset += 1;
247→                }
248→                if executing.system.cpi_context.is_some() {
249→                    offset += 1;
250→                }
