259→                // When deduplicated=true, the duplicate queue is in the outer instruction but not in CPI slice
260→                if executing.tokens_out_queue.is_some() && !deduplicated {
261→                    offset += 1;
262→                }
263→            }
264→            offset
265→        }
266→    }
