430→            .unwrap_or_default();
431→
432→        // Check if DecompressMint action is present
433→        let has_decompress_mint_action = parsed_instruction_data
434→            .actions
435→            .iter()
436→            .any(|action| matches!(action, ZAction::DecompressMint(_)));
437→
438→        // Check if CompressAndCloseCMint action is present
439→        let has_compress_and_close_cmint_action = parsed_instruction_data
440→            .actions
441→            .iter()
442→            .any(|action| matches!(action, ZAction::CompressAndCloseMint(_)));
443→
444→        // Validation: Cannot combine DecompressMint and CompressAndCloseCMint in the same instruction
445→        if has_decompress_mint_action && has_compress_and_close_cmint_action {
446→            msg!("Cannot combine DecompressMint and CompressAndCloseCMint in the same instruction");
447→            return Err(ErrorCode::CannotDecompressAndCloseInSameInstruction.into());
448→        }
449→
450→        // Validation: CompressAndCloseCMint must be the only action
451→        if has_compress_and_close_cmint_action && parsed_instruction_data.actions.len() != 1 {
452→            msg!("CompressAndCloseCMint must be the only action in the instruction");
453→            return Err(ErrorCode::CompressAndCloseCMintMustBeOnlyAction.into());
454→        }
455→
456→        // Validation: Cannot combine create_mint with CompressAndCloseCMint
457→        if has_compress_and_close_cmint_action && parsed_instruction_data.create_mint.is_some() {
458→            msg!("Cannot combine create_mint with CompressAndCloseCMint");
459→            return Err(ErrorCode::CompressAndCloseCMintMustBeOnlyAction.into());
460→        }
461→
462→        // We need mint signer only if creating a new mint.
463→        // CompressAndCloseCMint does NOT need mint_signer - it verifies CMint by compressed_mint.metadata.mint
464→        let with_mint_signer = parsed_instruction_data.create_mint.is_some();
465→        // CMint account needed when mint is already decompressed (metadata flag)
466→        // When mint is None, CMint is decompressed (data lives in CMint account, compressed account is empty)
467→        let cmint_decompressed = parsed_instruction_data.mint.is_none();
468→
469→        if write_to_cpi_context {
470→            // Cannot create a compressed mint when writing to CPI context.
471→            // Mint creation charges the creation fee and requires the rent_sponsor account,
472→            // which is not available in the CPI context write path.
473→            if parsed_instruction_data.create_mint.is_some() {
474→                msg!("Compressed mint creation not allowed when writing to cpi context");
475→                return Err(ErrorCode::CpiContextSetNotUsable.into());
476→            }
477→
478→            // Must not have any MintToCToken actions
479→            let has_mint_to_ctoken_actions = parsed_instruction_data
480→                .actions
481→                .iter()
482→                .any(|action| matches!(action, ZAction::MintTo(_)));
483→            if has_mint_to_ctoken_actions {
484→                msg!("Mint to ctokens not allowed when writing to cpi context");
