501→                with_cpi_context,
502→                write_to_cpi_context,
503→                cmint_decompressed,
504→                require_token_output_queue,
505→                with_mint_signer,
506→                create_mint: parsed_instruction_data.create_mint.is_some(),
507→                has_decompress_mint_action,
508→                has_compress_and_close_cmint_action,
509→            })
